def embedding_doc(tokens, gensim_emb, n):
  """
  Función que calcula el vector medio de una lista de
  tokens
  """
  lista = list()
  for i in tokens:
    try:
      lista.append(gensim_emb.get_vector(i) )
    except:
      continue

  try:
    resultado = np.mean(lista, axis=0)
  except:
    resultado = np.zeros(n)
  return resultado
